{"content": """"config_reader 模块的 pytest 测试，使用 mock 文件系统。"""

import json
from pathlib import Path
from unittest.mock import MagicMock, mock_open, patch

import pytest

from config_reader import Config, get_value, load_config


@pytest.fixture
def sample_config_data() -> dict[str, any]:
    """示例配置数据。"""
    return {
        "database": {
            "host": "localhost",
            "port": 3306,
            "timeout": 30,
        },
        "app": {
            "name": "test_app",
            "debug": True,
        },
        "version": "1.0.0",
    }


@pytest.fixture
def sample_config_json(sample_config_data: dict[str, any]) -> str:
    """示例配置 JSON 字符串。"""
    return json.dumps(sample_config_data)


class TestConfig:
    """Config dataclass 测试。"""

    def test_config_frozen(self, sample_config_data: dict[str, any]) -> None:
        """测试 Config 是不可变的（frozen）。"""
        config = Config(data=sample_config_data)

        with pytest.raises(Exception):  # FrozenInstanceError
            config.data = {}  # type: ignore

    def test_from_file_success(
        self,
        sample_config_data: dict[str, any],
        sample_config_json: str,
    ) -> None:
        """测试成功从文件加载配置。"""
        mock_path = Path("/fake/config.json")

        with patch.object(Path, "exists", return_value=True):
            with patch.object(Path, "read_text", return_value=sample_config_json):
                config = Config.from_file(mock_path)

                assert config.data == sample_config_data
                assert isinstance(config, Config)

    def test_from_file_not_found(self) -> None:
        """测试文件不存在时抛出 FileNotFoundError。"""
        mock_path = Path("/fake/nonexistent.json")

        with patch.object(Path, "exists", return_value=False):
            with pytest.raises(FileNotFoundError, match="配置文件不存在"):
                Config.from_file(mock_path)

    def test_from_file_invalid_json(self) -> None:
        """测试无效 JSON 时抛出 JSONDecodeError。"""
        mock_path = Path("/fake/invalid.json")
        invalid_json = "{invalid json content"

        with patch.object(Path, "exists", return_value=True):
            with patch.object(Path, "read_text", return_value=invalid_json):
                with pytest.raises(json.JSONDecodeError):
                    Config.from_file(mock_path)

    def test_from_file_with_string_path(
        self,
        sample_config_json: str,
    ) -> None:
        """测试接受字符串路径。"""
        with patch.object(Path, "exists", return_value=True):
            with patch.object(Path, "read_text", return_value=sample_config_json):
                config = Config.from_file("/fake/config.json")

                assert isinstance(config, Config)

    def test_get_value_simple_key(self, sample_config_data: dict[str, any]) -> None:
        """测试获取简单键值。"""
        config = Config(data=sample_config_data)

        assert config.get_value("version") == "1.0.0"

    def test_get_value_nested_key(self, sample_config_data: dict[str, any]) -> None:
        """测试获取嵌套键值（点号分隔）。"""
        config = Config(data=sample_config_data)

        assert config.get_value("database.host") == "localhost"
        assert config.get_value("database.port") == 3306
        assert config.get_value("app.debug") is True

    def test_get_value_deep_nested_key(self) -> None:
        """测试获取深层嵌套键值。"""
        config = Config(
            data={
                "level1": {
                    "level2": {
                        "level3": {
                            "value": "deep",
                        },
                    },
                },
            }
        )

        assert config.get_value("level1.level2.level3.value") == "deep"

    def test_get_value_missing_key_returns_default(
        self,
        sample_config_data: dict[str, any],
    ) -> None:
        """测试缺失键时返回默认值。"""
        config = Config(data=sample_config_data)

        assert config.get_value("nonexistent", "default") == "default"
        assert config.get_value("database.nonexistent", 9999) == 9999

    def test_get_value_missing_key_returns_none(
        self,
        sample_config_data: dict[str, any],
    ) -> None:
        """测试缺失键且无默认值时返回 None。"""
        config = Config(data=sample_config_data)

        assert config.get_value("nonexistent") is None
        assert config.get_value("database.nonexistent") is None

    def test_get_value_partial_path_returns_default(
        self,
        sample_config_data: dict[str, any],
    ) -> None:
        """测试部分路径不存在时返回默认值。"""
        config = Config(data=sample_config_data)

        assert config.get_value("nonexistent.nested.key", "fallback") == "fallback"


class TestLoadConfig:
    """load_config 便捷函数测试。"""

    def test_load_config_returns_config_instance(
        self,
        sample_config_json: str,
    ) -> None:
        """测试 load_config 返回 Config 实例。"""
        with patch.object(Path, "exists", return_value=True):
            with patch.object(Path, "read_text", return_value=sample_config_json):
                config = load_config("/fake/config.json")

                assert isinstance(config, Config)

    def test_load_config_with_path_object(
        self,
        sample_config_json: str,
    ) -> None:
        """测试 load_config 接受 Path 对象。"""
        mock_path = Path("/fake/config.json")

        with patch.object(Path, "exists", return_value=True):
            with patch.object(Path, "read_text", return_value=sample_config_json):
                config = load_config(mock_path)

                assert isinstance(config, Config)


class TestGetValue:
    """get_value 便捷函数测试。"""

    def test_get_value_function(self, sample_config_data: dict[str, any]) -> None:
        """测试 get_value 便捷函数。"""
        config = Config(data=sample_config_data)

        assert get_value(config, "database.host") == "localhost"
        assert get_value(config, "nonexistent", "default") == "default"

    def test_get_value_function_with_none_default(
        self,
        sample_config_data: dict[str, any],
    ) -> None:
        """测试 get_value 便捷函数默认返回 None。"""
        config = Config(data=sample_config_data)

        assert get_value(config, "nonexistent") is None


class TestEdgeCases:
    """边界情况测试。"""

    def test_empty_config(self) -> None:
        """测试空配置。"""
        config = Config(data={})

        assert config.get_value("any.key") is None
        assert config.get_value("any.key", "default") == "default"

    def test_config_with_none_values(self) -> None:
        """测试包含 None 值的配置。"""
        config = Config(data={"nullable": None})

        assert config.get_value("nullable") is None
        assert config.get_value("nullable", "default") is None

    def test_config_with_empty_string_key(self) -> None:
        """测试空字符串键。"""
        config = Config(data={"": "empty_key_value"})

        assert config.get_value("") == "empty_key_value"

    def test_config_with_numeric_values(self) -> None:
        """测试数值类型配置。"""
        config = Config(
            data={
                "int_value": 42,
                "float_value": 3.14,
                "bool_value": False,
            }
        )

        assert config.get_value("int_value") == 42
        assert config.get_value("float_value") == 3.14
        assert config.get_value("bool_value") is False

    def test_config_with_list_values(self) -> None:
        """测试列表类型配置。"""
        config = Config(data={"servers": ["server1", "server2", "server3"]})

        servers = config.get_value("servers")
        assert isinstance(servers, list)
        assert len(servers) == 3
